<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Lawn Service Promotion</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            margin: 0;
            padding: 0;
        }
       .container {
            width: 600px;
            margin: auto;
            padding: 20px;
        }
       .header {
            background-color: #4CAF50;
            color: white;
            padding: 20px;
            text-align: center;
        }
       .content {
            padding: 20px;
        }
       .promotion {
            background-color: #f9f9f9;
            padding: 20px;
            border-radius: 5px;
            margin-bottom: 20px;
        }
       .promotion h1 {
            color: #4CAF50;
        }
       .promotion p {
            color: #333;
        }
       .image {
            text-align: center;
        }
       .image img {
            max-width: 100%;
            height: auto;
        }
       .cta-button {
            display: inline-block;
            padding: 10px 20px;
            background-color: #4CAF50;
            color: white;
            text-decoration: none;
            border-radius: 5px;
        }
       .cta-button:hover {
            background-color: #45a049;
        }
       .footer {
            background-color: #f1f1f1;
            padding: 10px;
            text-align: center;
        }
       .unsubscribe {
            color: #333;
            text-decoration: none;
            margin-top: 10px;
        }
       .unsubscribe:hover {
            text-decoration: underline;
        }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h1>Lawn Service Special Offer</h1>
        </div>
        <div class="content">
            <div class="promotion">
                <h1>Spring Cleaning: 20% Off</h1>
